<template>
  <div :id="chartId" :class="chartClass" ref="chartContainer"></div>
</template>

<script>
import '@/assets/flow.css';

export default {
  name: 'RBillingFlowChart',
  props: {
    data: { type: Array, required: true },
    chartId: { type: String, default: 'BillingFlowChart' },
    chartClass: { type: String, default: 'RBillingflowChart' },
    isBillingType :{type: Boolean,required: false}
  },
  data() {
    return {
      globalServiceText: 1
    };
  },
  mounted() {
    this.buildFlowChart();
  },
  methods: {
    buildFlowChart() {
      const container = this.$refs.chartContainer;
      container.innerHTML = '';

      const ulRoot = document.createElement('ul');
      ulRoot.className = 'fc_parentchild';

      const liRoot = document.createElement('li');
      liRoot.className = 'arrowdown';

      const rootNode = this.buildNodeStructure(null, 0);
      liRoot.appendChild(rootNode);
      ulRoot.appendChild(liRoot);

      // Sort by nodeName in natural order first, then by displayOrder as secondary sort
      // Filter out items without serviceName to prevent blue diamond RootRule nodes
      const sortedData = [...this.data]
        .filter(item => item && item.serviceName)
        .sort((a, b) => {
          // First sort by nodeName using natural sort
          const nodeNameCompare = this.naturalSort(a, b);
          if (nodeNameCompare !== 0) {
            return nodeNameCompare;
          }
          // If nodeName is same, then sort by displayOrder
          const orderA = a.displayOrder ?? 0;
          const orderB = b.displayOrder ?? 0;
          return orderA - orderB;
        });

      sortedData.forEach((item) => {
        const li = document.createElement('li');
        const ulChild = document.createElement('ul');
        if (!item.nodeName || item.nodeName.indexOf('.') === -1) {
          li.className = 'arrowdown';
        } else {
          ulChild.className = 'fc_subchild';
        }

        const mainNode = this.buildNodeStructure(item, item.displayOrder || 0);
        li.appendChild(mainNode);

        if ((item.isLeafNode && !item.isAddOn) || item.isAddOn) {
          if(this.isBillingType == true){
            const rightBranch = this.buildFlowChartRightNew(item);
            li.appendChild(rightBranch);
          }
          else{
            const rightBranch = this.buildFlowChartRightUtility(item);
            li.appendChild(rightBranch);
          }
          
        }

        ulRoot.appendChild(li);
      });

      container.appendChild(ulRoot);
      this.adjustWidth(container);
    },

    naturalSort(a, b) {
      const nodeNameA = (a.nodeName || '').toString().trim();
      const nodeNameB = (b.nodeName || '').toString().trim();
      
      // Handle empty nodeNames
      if (!nodeNameA && !nodeNameB) return 0;
      if (!nodeNameA) return 1;
      if (!nodeNameB) return -1;
      
      // Try to parse as numbers for natural sort (handles "1", "2", "2.1", etc.)
      const partsA = nodeNameA.split('.').map(part => {
        const num = Number(part);
        return isNaN(num) ? part : num;
      });
      const partsB = nodeNameB.split('.').map(part => {
        const num = Number(part);
        return isNaN(num) ? part : num;
      });
      
      const len = Math.max(partsA.length, partsB.length);

      for (let i = 0; i < len; i++) {
        const valA = partsA[i] ?? '';
        const valB = partsB[i] ?? '';
        
        // If both are numbers, compare numerically
        if (typeof valA === 'number' && typeof valB === 'number') {
          if (valA !== valB) return valA - valB;
        } else {
          // Otherwise compare as strings
          const strA = String(valA);
          const strB = String(valB);
          if (strA !== strB) {
            return strA.localeCompare(strB, undefined, { numeric: true, sensitivity: 'base' });
          }
        }
      }
      return 0;
    },

    buildNodeStructure(data, level) {
      const p = document.createElement('p');
      const isRootRule = !data || !data.serviceName;
      // Always use shape_oval for RootRule nodes, regardless of level
      p.className = (level <= 0 || isRootRule) ? 'shape_oval' : 'shape_polygan';

      const titleSpan = document.createElement('span');
      titleSpan.style.fontWeight = '700';
      titleSpan.style.marginTop = level <= 0 ? '25px' : '0px';
      if (isRootRule) {
        titleSpan.textContent = this.$t?.('RootRule') || 'Root Rule';
        p.appendChild(titleSpan);
        return p;
      }

      let serviceName = data.serviceName || '';
      if (serviceName.includes('~GLOBAL~')) {
        serviceName = serviceName
          .replace(/~NODENAME~/g, this.$t?.('Global') || 'Global')
          .replace(/~GLOBAL~/g, String(this.globalServiceText++));
      } else {
        serviceName = serviceName.replace(/~NODENAME~/g, this.$t?.('Rule') || 'Rule');
      }

      const parts = serviceName.split('AND');
      parts.forEach((part, idx) => {
        if (idx > 0) {
          const andSpan = document.createElement('span');
          andSpan.textContent = 'And';
          andSpan.style.fontWeight = 400;
          p.appendChild(andSpan);
        }
        const partSpan = document.createElement('span');
        partSpan.textContent = part.trim();
        partSpan.title = part.trim();
        partSpan.style.fontWeight = 'bold';
        p.appendChild(partSpan);
      });

      return p;
    },

    buildFlowChartRightNew(item) {
      const ul = document.createElement('ul');
      ul.className = 'fc_subchild';

      const createOvalNode = (label, contentHtml = '&nbsp;', flagClass = '') => {
        const li = document.createElement('li');
        li.className = 'arrowright';

        const p = document.createElement('p');
        p.className = 'shape_oval';
        
        if (flagClass) p.classList.add(flagClass);
        if (flagClass !== "" && label == null) label = "Flag";

        const spanText = document.createElement('span');
        spanText.className = 'textbetweenline';
        spanText.innerHTML = contentHtml;

        const spanName = document.createElement('span');
        spanName.style.marginTop = '25px';
        spanName.style.fontWeight = 'bold';
        spanName.textContent = label;

        p.appendChild(spanText);
        p.appendChild(spanName);
        li.appendChild(p);
        return li;
      };

      const getLimitHtml = (item) => {
        if (item.isLimit) {
          const limit = item.limit || 0;
          const day = item.dayLimit || 0;
          if (limit > 0 && day > 0) return `Limit: ${limit}<br/>Days: ${day}`;
          if (limit > 0) return `Limit: ${limit}`;
          if (day > 0) return `Days: ${day}`;
        }
        return '&nbsp;';
      };

      const flagClass = this.getFlagClass(item.clientServiceFlag);

      if (item.addOnType === 'C' && item.isLeafNode && item.isAddOn) {
        const li = createOvalNode(item.addonWorkCode || item.workCodeName, getLimitHtml(item), flagClass);
        ul.appendChild(li);
      }

      if (item.isLeafNode && item.isAddOn) {
        const li = document.createElement('li');
        li.className = 'arrowright';
        const p = document.createElement('p');
        p.className = 'hoctagon';

        const img = document.createElement('img');
        img.src = 'https://talygenv.github.io/Vue-UI-Content/images/billingRule/loop.png';
        if (item.addOnType === 'C') img.style.display = 'none';

        const span = document.createElement('span');
        span.style.fontWeight = 'bold';
        span.textContent = `${item.addOnFieldName} > ${item.addOnValue}`;

        p.appendChild(img);
        p.appendChild(span);
        li.appendChild(p);
        ul.appendChild(li);
      }

      if (item.addOnType !== 'C') {
        const li = createOvalNode(item.addonWorkCode || item.workCodeName, getLimitHtml(item), flagClass);
        ul.appendChild(li);
      }

      const parentId = item.isAddOn ? item.addonWorkCodeId : item.workCodeId;
      const match = (item.billingLimitWorkCode || []).find(val => val.workCodeId === parentId);
      if (match) {
        this.buildFlowChartChild(ul, match, item.billingLimitWorkCode, parentId);
      }

      return ul;
    },
    
    
    buildFlowChartRightUtility(item) {
        const ul = document.createElement('ul');
        ul.className = 'fc_subchild';

        // Function to create the oval shape node
        const createOvalNode = (label, contentHtml = '&nbsp;', flagClass = '') => {
          const li = document.createElement('li');
          li.className = 'arrowright';

          const p = document.createElement('p');
          if(item.addOnType == null  ||  item.addOnType == ''){
            p.className = 'shape_oval';
          }
          else{
            p.className = 'shape_oval shape_ovalnew';
          }
          

          if (flagClass) p.classList.add(flagClass);
          if (flagClass !== "" && label == null) label = "Flag";

          const spanText = document.createElement('span');
          spanText.className = 'textbetweenline';
          spanText.innerHTML = contentHtml;

          const spanName = document.createElement('span');
          spanName.style.marginTop = '25px';
          spanName.style.fontWeight = 'bold';
          spanName.innerHTML = label;
          p.appendChild(spanText);
          if(item.addOnType == null  ||  item.addOnType == ''){
            p.appendChild(spanName);
          }
          li.appendChild(p);
          return li;
        };

        // Function to get limit details
        const getLimitHtml = (item) => {
          if (item.isLimit) {
            const limit = item.limit || 0;
            const day = item.dayLimit || 0;
            if (limit > 0 && day > 0) return `Limit: ${limit}<br/>Days: ${day}`;
            if (limit > 0) return `Limit: ${limit}`;
            if (day > 0) return `Days: ${day}`;
          }
          return '&nbsp;';
        };

        const flagClass = this.getFlagClass(item.clientServiceFlag);

        // CASE 1: Add-on type 'C'
        if (item.addOnType === 'C' && item.isLeafNode && item.isAddOn) {
          const li = createOvalNode(item.addonWorkCode || item.workCodeName, getLimitHtml(item), flagClass);
          ul.appendChild(li);
        }

        // CASE 2: Other Add-on types (non-'C')
        if (item.addOnType !== 'C') {
          let table = null;
          let tbody = null;

          if (item.addonDetail != null) {
            // Create the table dynamically
            table = document.createElement('table');
            table.className = 'slab-table'; // optional class for styling

            const thead = document.createElement('thead');
            const headerRow = document.createElement('tr');
            ['From', 'To', 'Rate Code'].forEach(text => {
              const th = document.createElement('th');
              th.textContent = text;
              headerRow.appendChild(th);
            });
            thead.appendChild(headerRow);
            table.appendChild(thead);

            tbody = document.createElement('tbody');
            table.appendChild(tbody);

            // Parse JSON safely
            let slabs = [];
            try {
              slabs = JSON.parse(item.addonDetail);
            } catch (e) {
              console.error("Invalid addonDetail JSON", e);
              slabs = [];
            }

            // Build each slab row
            slabs.forEach(slab => {
              const toValue = slab && slab.hasOwnProperty('addon_to_value') && slab.addon_to_value !== null ? slab.addon_to_value : '∞';
              // const toValue = slab.addon_to_value === null ? '∞' : slab.addon_to_value;
              const rateCode = slab.work_code;
              // `SLAB ${slab.addon_from_value} To ${toValue === 'null' ? 'Infinity' : toValue}`;

              const tr = document.createElement('tr');

              const tdFrom = document.createElement('td');
              tdFrom.textContent = slab.addon_from_value;
              tr.appendChild(tdFrom);

              const tdTo = document.createElement('td');
              tdTo.textContent = toValue;
              tr.appendChild(tdTo);

              const tdRate = document.createElement('td');
              const spanLabel = document.createElement('span');
              spanLabel.className = 'slab-label';
              spanLabel.textContent = rateCode;
              tdRate.appendChild(spanLabel);
              tr.appendChild(tdRate);

              tbody.appendChild(tr);
            });
          }
          // Create the oval node and insert the table inside it
          const li = createOvalNode(item.addonWorkCode || item.workCodeName, getLimitHtml(item), flagClass);

          // Append table inside the oval node (not the document body)
          if (table) {
            li.querySelector('p').appendChild(table);
          }

          ul.appendChild(li);
        }

        // Continue building the flowchart
        const parentId = item.isAddOn ? item.addonWorkCodeId : item.workCodeId;
        const match = (item.billingLimitWorkCode || []).find(val => val.workCodeId === parentId);
        if (match) {
          this.buildFlowChartChild(ul, match, item.billingLimitWorkCode, parentId);
        }

        return ul;
    },

    buildFlowChartChild(ul, node, list, parentId) {
      if (!node) return;
      const p = document.createElement('p');
      p.className = 'shape_oval';

      const spanText = document.createElement('span');
      spanText.className = 'textbetweenline';
      if (node.limit > 0 && node.daysLimit > 0) {
        spanText.innerHTML = `Limit: ${node.limit}<br/>Days: ${node.daysLimit}`;
      } else if (node.limit > 0) {
        spanText.innerHTML = `Limit: ${node.limit}`;
      } else if (node.daysLimit > 0) {
        spanText.innerHTML = `Days: ${node.daysLimit}`;
      } else {
        spanText.innerHTML = '&nbsp;';
      }

      const spanName = document.createElement('span');
      spanName.style.marginTop = '25px';
      spanName.style.fontWeight = 'bold';
      spanName.textContent = node.alternateWorkCode;

      p.appendChild(spanText);
      p.appendChild(spanName);

      const li = document.createElement('li');
      li.className = 'arrowright';
      li.appendChild(p);
      ul.appendChild(li);

      const next = list.find(n => n.workCodeId === node.alternateWorkCodeId);
      if (next && next.workCodeId !== parentId) {
        this.buildFlowChartChild(ul, next, list, node.alternateWorkCodeId);
      }
    },

    getFlagClass(flag) {
      switch (String(flag || '').trim()) {
        case 'R': return 'oval_red';
        case 'G': return 'oval_green';
        case 'Y': return 'oval_yellow';
        default: return '';
      }
    },

    adjustWidth(container) {
      const rightCounts = Array.from(container.querySelectorAll('ul.fc_subchild')).map(ul =>
        ul.querySelectorAll('li.arrowright').length
      );
      const max = Math.max(...rightCounts, 4);
      container.style.width = Math.max(window.innerWidth - 100, max * 350) + 'px';
    }
  }
};
</script>

<style>
.fc_parentchild li p.shape_oval.shape_ovalnew{height: auto!important; padding:10px;}
p.shape_oval.shape_ovalnew table th {
    font-size: 13px;
    font-weight: 600;
}
p.shape_oval.shape_ovalnew table td {
    font-size: 12px;
    font-weight: 400; padding:0px;line-height: 8px;
}
</style>